var yr = {};

// Присваиваем функцию yr_request глобальному объекту global
global.yr_request = function() {
    yr.error = false;
    if (GlobalVariables.last_yr_refresh_time && ((Date.now() - GlobalVariables.last_yr_refresh_time) < global.short_refresh_time * 1000)) {
        yr.error_code = ("Ограничение количества запросов в Yr.no. Осталось ждать " + (global.short_refresh_time - (Date.now() - GlobalVariables.last_yr_refresh_time) / 1000).toFixed(0) + " секунд");
        yr.error = true;
        return yr;
    }
    try {
        var yr_no = JSON.parse(HttpClient.GET("https://api.met.no/weatherapi/locationforecast/2.0/complete.json?${global.coordinates}")
            .header("User-Agent", "Mozilla/5.0 (Macintosh; Intel Mac OS X 10.9; rv:50.0) Gecko/20100101")
            .send()
            .getBody()
        );
    } catch (e) {
        delete yr.temp;
        yr.error = true;
        yr.error_code = e.message;
        return yr;
    }

    yr.time = global.zulu_time(yr_no.properties.timeseries[0].time);
    yr.pressure = (yr_no.properties.timeseries[0].data.instant.details.air_pressure_at_sea_level * 0.75006156).toFixed(1);
    yr.temp = yr_no.properties.timeseries[0].data.instant.details.air_temperature;
    yr.cloud = yr_no.properties.timeseries[0].data.instant.details.cloud_area_fraction;
    yr.dewpoint = yr_no.properties.timeseries[0].data.instant.details.dew_point_temperature;
    yr.fog = yr_no.properties.timeseries[0].data.instant.details.fog_area_fraction;
    yr.hum = yr_no.properties.timeseries[0].data.instant.details.relative_humidity;
    yr.uv = yr_no.properties.timeseries[0].data.instant.details.ultraviolet_index_clear_sky;
    yr.wind_deg = yr_no.properties.timeseries[0].data.instant.details.wind_from_direction;
    yr.wind_dir = global.wind_deg_text(yr_no.properties.timeseries[0].data.instant.details.wind_from_direction);
    yr.wind = yr_no.properties.timeseries[0].data.instant.details.wind_speed;
    yr.condition_1_hour = global.cond_text(yr_no.properties.timeseries[0].data.next_1_hours.summary.symbol_code);
    yr.condition_6_hours = global.cond_text(yr_no.properties.timeseries[0].data.next_6_hours.summary.symbol_code);
    yr.condition_12_hours = global.cond_text(yr_no.properties.timeseries[0].data.next_12_hours.summary.symbol_code);
    yr.temp_max_6_hours = yr_no.properties.timeseries[0].data.next_6_hours.details.air_temperature_max;
    yr.temp_min_6_hours = yr_no.properties.timeseries[0].data.next_6_hours.details.air_temperature_min;
    yr.prec = yr_no.properties.timeseries[0].data.next_6_hours.details.precipitation_amount;
    GlobalVariables.last_yr_refresh_time = Date.now();
    return yr;
};
